INSERT INTO `v1_7076d946a09d6004ba5b5a8a033ecde2aa0ed2c0bdafb45ee11712843858732a` VALUES (11300102, 7, 10, 8, "vo_minigame_1012_result_1001", 3001, "すごいじゃない…全問正解よ！\nま、当然といや当然よね～\nだってあたしが\n教えてやってんだから♪", 1, 1, 10, 10, 1, 3.33);
