INSERT INTO `v1_7076d946a09d6004ba5b5a8a033ecde2aa0ed2c0bdafb45ee11712843858732a` VALUES (11300127, 7, 4, 8, "vo_minigame_1012_result_1026", 3001, "難問揃いでこの正解率は\n大したもんよ！\nま、もっといい点取りたいんなら\n勉強、付き合ったげるわ！", 3, 1, 0, 6, 1, 3.72);
INSERT INTO `v1_7076d946a09d6004ba5b5a8a033ecde2aa0ed2c0bdafb45ee11712843858732a` VALUES (11300128, 2, 1, 3, "vo_minigame_1012_result_1027", 3001, "なるほど…\nこれは教えがいがあるわね\nビシバシ鍛えてやるから\n覚悟しなさい！", 1, 1, 1, 3, 1, 3.5);
INSERT INTO `v1_7076d946a09d6004ba5b5a8a033ecde2aa0ed2c0bdafb45ee11712843858732a` VALUES (11300129, 2, 1, 4, "vo_minigame_1012_result_1028", 3001, "ちょっとあんた、\n全然できてないじゃない！\n…まさかこれが本気だなんて\n言わないわよね～？", 1, 1, 1, 3, 1, 3.25);
