INSERT INTO `v1_7076d946a09d6004ba5b5a8a033ecde2aa0ed2c0bdafb45ee11712843858732a` VALUES (11300136, 1, 1, 3, "vo_minigame_1012_result_1035", 3001, "なんとか０点は免れたわね…\n難問揃いだけど、\nもっと頑張っていきましょ！", 3, 1, 0, 3, 1, 3.1);
