INSERT INTO `v1_7076d946a09d6004ba5b5a8a033ecde2aa0ed2c0bdafb45ee11712843858732a` VALUES (12300148, 1, 5, 1, "vo_minigame_1012_result_1080", 3001, "まあまあな点数だけど、\n自分的に手ごたえはどう？\nダメだって思ってんなら、\nまだまだ伸びる余地ありね！", 1, 2, 0, 9, 1, 0.0);
INSERT INTO `v1_7076d946a09d6004ba5b5a8a033ecde2aa0ed2c0bdafb45ee11712843858732a` VALUES (12300149, 1, 5, 8, "vo_minigame_1012_result_1081", 3001, "うん、中々の出来ね！\nでもあんたはもっといい点\n取れるはずよ！\nもっと頑張りましょうか！", 2, 2, 0, 9, 1, 2.21);
INSERT INTO `v1_7076d946a09d6004ba5b5a8a033ecde2aa0ed2c0bdafb45ee11712843858732a` VALUES (12300150, 1, 5, 3, "vo_minigame_1012_result_1082", 3001, "ん～はっきり言って微妙ね！\nま、難しい問題だし、\n勉強すれば\n点数は上がっていくと思うわ！", 2, 2, 0, 9, 1, 2.46);
INSERT INTO `v1_7076d946a09d6004ba5b5a8a033ecde2aa0ed2c0bdafb45ee11712843858732a` VALUES (12300151, 1, 5, 3, "vo_minigame_1012_result_1083", 3001, "ん～…\n10点には届かなかったか～\n次は10点越え目指して\n頑張ってみない？", 2, 2, 0, 9, 1, 2.94);
INSERT INTO `v1_7076d946a09d6004ba5b5a8a033ecde2aa0ed2c0bdafb45ee11712843858732a` VALUES (12300152, 1, 5, 7, "vo_minigame_1012_result_1084", 3001, "はいお疲れ～\n点数的にはまあまあってとこね！\nま、超難問だし頑張ったわよ", 3, 2, 0, 9, 1, 4.19);
INSERT INTO `v1_7076d946a09d6004ba5b5a8a033ecde2aa0ed2c0bdafb45ee11712843858732a` VALUES (12300153, 1, 5, 1, "vo_minigame_1012_result_1085", 3001, "うん、かなり難しい問題なのに\n最後までやり遂げたわね\n次はもっといい点目指してみる？", 3, 2, 0, 9, 1, 0.0);
INSERT INTO `v1_7076d946a09d6004ba5b5a8a033ecde2aa0ed2c0bdafb45ee11712843858732a` VALUES (12300154, 1, 5, 3, "vo_minigame_1012_result_1086", 3001, "ちょっとミスが多かったかもね～\nでも間違えた所は復習して\n次は正解するわよー！", 3, 2, 0, 9, 1, 2.63);
INSERT INTO `v1_7076d946a09d6004ba5b5a8a033ecde2aa0ed2c0bdafb45ee11712843858732a` VALUES (12300155, 1, 1, 3, "vo_minigame_1012_result_1087", 3001, "あら…あんまり良くない点数ね～\nどうしたの、調子でも悪かった？\n次はもっと頑張りましょうか", 1, 2, 0, 4, 1, 5.53);
INSERT INTO `v1_7076d946a09d6004ba5b5a8a033ecde2aa0ed2c0bdafb45ee11712843858732a` VALUES (12300156, 3, 1, 3, "vo_minigame_1012_result_1088", 3001, "ん～…正解数は\n物足りないわね～\nもうちょっと勉強の時間\n増やしちゃおっか？", 1, 2, 9, 4, 1, 0.01);
INSERT INTO `v1_7076d946a09d6004ba5b5a8a033ecde2aa0ed2c0bdafb45ee11712843858732a` VALUES (12300157, 1, 1, 3, "vo_minigame_1012_result_1089", 3001, "ん～…あんたならもうちょと\nいい点取れんでしょ～？\nもっと頑張んなさいよ\n期待してやってんだからさ！", 1, 2, 3, 4, 1, 4.15);
INSERT INTO `v1_7076d946a09d6004ba5b5a8a033ecde2aa0ed2c0bdafb45ee11712843858732a` VALUES (12300158, 9, 1, 9, "vo_minigame_1012_result_1090", 3001, "ん～今のあんたには、\nこの問題は難しかったかしら…\n難易度下げてチャレンジするのも\nありかもね～？", 2, 2, 9, 4, 1, 0.01);
