INSERT INTO `v1_7076d946a09d6004ba5b5a8a033ecde2aa0ed2c0bdafb45ee11712843858732a` VALUES (12300160, 1, 1, 3, "vo_minigame_1012_result_1092", 3001, "なるほど…\nちょっと苦手な問題が多かった？\nもう一度チャレンジ\nしてみましょうか～", 2, 2, 0, 4, 1, 1.44);
INSERT INTO `v1_7076d946a09d6004ba5b5a8a033ecde2aa0ed2c0bdafb45ee11712843858732a` VALUES (12300161, 3, 1, 3, "vo_minigame_1012_result_1093", 3001, "んん～…問題が難しすぎた？\n無理に難しい問題続けるより、\n難易度下げた方が\n勉強の効率良いかもよ～？", 3, 2, 0, 4, 1, 0.0);
INSERT INTO `v1_7076d946a09d6004ba5b5a8a033ecde2aa0ed2c0bdafb45ee11712843858732a` VALUES (12300162, 9, 1, 3, "vo_minigame_1012_result_1094", 3001, "…あんまり点数取れなかったわね\nこれはあたしにも難しい問題だし\nそう落ち込まなくても大丈夫！\n次頑張りましょ！", 3, 2, 3, 4, 1, 2.91);
INSERT INTO `v1_7076d946a09d6004ba5b5a8a033ecde2aa0ed2c0bdafb45ee11712843858732a` VALUES (12300163, 1, 1, 5, "vo_minigame_1012_result_1095", 3001, "ごめん、ちょっと難しすぎた？\nもう一度チャレンジするも良し、\n難易度を下げるも良し、\nあんたがやる気なら付き合うわ！", 3, 2, 0, 4, 1, 2.61);
INSERT INTO `v1_7076d946a09d6004ba5b5a8a033ecde2aa0ed2c0bdafb45ee11712843858732a` VALUES (12300164, 2, 0, 4, "vo_minigame_1012_result_1096", 3001, "ちょっとあんた…\nやる気ないわよね～！？\n次こんな点数取ったら\n怒るわよ！", 1, 2, 1, 0, 1, 3.63);
